class internal_metadata_pre:
    # BEGIN DEFAULT_CAPITALISATION_SCHEME
    DEFAULT_CAPITALISATION_SCHEME = "upper-camel"

    # END DEFAULT_CAPITALISATION_SCHEME
    # BEGIN DEFAULT_INDENTATION
    DEFAULT_INDENTATION = 2

    # END DEFAULT_INDENTATION
    # BEGIN DEFAULT_MAX_GAP
    DEFAULT_MAX_GAP = 10

    # END DEFAULT_MAX_GAP
    # BEGIN OWL_METACHARACTERS
    OWL_METACHARACTERS = [
        "(",
        ")",
        "[",
        "]",
        "{",
        "}",
        "/",
        ",",
        ":",
        ".",
        "'",
        '"',
        "\xa0",
        "#",
    ]

    # END OWL_METACHARACTERS
    # BEGIN Blocks
    Blocks = dict

    # END Blocks
    # BEGIN CellID
    CellID = str

    # END CellID
    # BEGIN XCoordinate
    XCoordinate = float

    # END XCoordinate
    # BEGIN YCoordinate
    YCoordinate = float

    # END YCoordinate
    # BEGIN Width
    Width = float

    # END Width
    # BEGIN Height
    Height = float

    # END Height
    # BEGIN ArrowStart
    ArrowStart = tuple

    # END ArrowStart
    # BEGIN ArrowEnd
    ArrowEnd = tuple

    # END ArrowEnd
    # BEGIN Label
    Label = str

    # END Label
    # BEGIN ArrowData
    ArrowData = tuple

    # END ArrowData
    # BEGIN Dimensions
    Dimensions = tuple

    # END Dimensions
    # BEGIN Paragraph
    Paragraph = str

    # END Paragraph
    # BEGIN Metacharacter
    Metacharacter = str

    # END Metacharacter
    # BEGIN Replacement
    Replacement = str

    # END Replacement
    # BEGIN get_prefixes
    def get_prefixes():
        return {
            "rico": "https://www.ica.org/standards/RiC/ontology#",
            "add": "https://data.archives.gov.on.test.gbad.ca/Schema/Description-Listings/",
            "auth": "https://data.archives.gov.on.test.gbad.ca/Schema/Authority/",
            "gbad": "https://data.archives.gov.on.test.gbad.ca/Schema/",
            "owl": "http://www.w3.org/2002/07/owl#",
            "rdfs": "http://www.w3.org/2000/01/rdf-schema#",
            "xsd": "http://www.w3.org/2001/XMLSchema#",
            "rdf": "http://www.w3.org/1999/02/22-rdf-syntax-ns#",
            "skos": "http://www.w3.org/2004/02/skos/core#",
        }

    # END get_prefixes
    # BEGIN get_ontology_iri
    def get_ontology_iri(qname: str | None = None) -> str:
        return f"ontology://generated-from-draw-io/{
            qname or datetime.strftime(datetime.now(), '%Y-%m-%dT%H-%M-%S')
        }"

    # END get_ontology_iri
    # BEGIN get_prefix
    def get_prefix() -> str | None:
        return os.getenv("PREFIX")

    # END get_prefix
    # BEGIN get_prefix_iri
    def get_prefix_iri(ontology_iri: str | None = None) -> str:
        return os.getenv("PREFIX_IRI", f"{ontology_iri or get_ontology_iri()}#")

    # END get_prefix_iri
    # BEGIN SerialisationConfig
    @dataclass(frozen=True)
    class SerialisationConfig:
        """
        Holds various user-configurable parameters for configuring the serialisation
        to OWL outputted by the 'serialise' function
        """

        infer_type_of_literals: bool
        include_preamble: bool
        ontology_iri: str | None
        prefix: str | None
        prefix_iri: str | None
        indentation: int
        include_label: bool

    # END SerialisationConfig


