class xml_data_core:
    # BEGIN NothingToParseException
    class NothingToParseException(Exception):
        """
        Can be thrown when calling the constructor of the DrawIOXMLTree class if the
        passed-in XML appears to define an empty graph
        """

    # END NothingToParseException
    # BEGIN NoSourceException
    class NoSourceException(Exception):
        """
        Can be thrown when calling the 'individuals_and_arrows' function if a given
        arrow has no source that can be identified
        """

        def __init__(self, message: str) -> None:
            super().__init__(message)

    # END NoSourceException
    # BEGIN NoTargetException
    class NoTargetException(Exception):
        """
        Can be thrown when calling the 'individuals_and_arrows' function if a given
        arrow has no target that can be identified
        """

        def __init__(self, message: str) -> None:
            super().__init__(message)

    # END NoTargetException
    # BEGIN _NoValueException
    class _NoValueException(Exception):
        pass

    # END _NoValueException
    # BEGIN _NoCellCloseEnoughException
    class _NoCellCloseEnoughException(Exception):
        pass

    # END _NoCellCloseEnoughException
    # BEGIN ParseException
    class ParseException(Exception):
        """
        Can be thrown if the XML being parsed does not have the anticipated
        structure in some respect
        """

        def __init__(self, message: str) -> None:
            super().__init__(message)

    # END ParseException
    # BEGIN NodeHTMLParser
    # override from strip_html.py
    class NodeHTMLParser(HTMLParser):
        """HTML parser mirroring the legacy behaviour while tracking raw markup."""

        def __init__(self) -> None:
            super().__init__()
            self._chunks: list[str] = []
            self._raw_html = ""

        def handle_starttag(self, tag: str, _: list[tuple[str, str | None]]) -> None:
            if tag in ["div", "blockquote", "p", "br"]:
                self._chunks.append(" ")

        def handle_endtag(self, tag: str) -> None:
            if tag in ["div", "blockquote", "p"]:
                self._chunks.append(" ")

        def handle_data(self, data: str) -> None:
            self._chunks.append(data)

        def feed(self, data: str) -> None:
            from html import unescape

            self._raw_html = unescape(data)
            super().feed(data)

        def _prettify_linebreaks(self) -> Generator[Paragraph, None, None]:
            previous_was_empty = False
            paragraph_already_handled = False
            current = ""
            for chunk in self._chunks:
                if not chunk:
                    if current:
                        yield current
                    current = ""
                    if previous_was_empty and (not paragraph_already_handled):
                        yield "\n\n"
                        paragraph_already_handled = True
                    else:
                        previous_was_empty = True
                    continue
                current += chunk
                previous_was_empty = False
                paragraph_already_handled = False
            if current:
                yield current

        def content(self) -> str:
            return "".join(self._prettify_linebreaks()).strip()

        def raw_html(self) -> str:
            return self._raw_html

        def clear(self) -> None:
            self._chunks = []
            self._raw_html = ""
            self.reset()

    # END NodeHTMLParser
    # BEGIN DrawIOXMLTree
    # override from cell_classifier.py
    class DrawIOXMLTree:
        """Deprecated. Use `DrawIOCellClassifier` instead."""

        def __init__(*args, **kwargs):
            raise pipeline.core.internal.data.DeimplementedException(
                DrawIOXMLTree.__doc__
            )

    # END DrawIOXMLTree


