# ===== core.rdf.data =====


class rdf_data_core:
    # BEGIN NotInKnownException
    class NotInKnownException(Exception):
        """
        Can be thrown if an arrow has a label which does not correspond to an
        object or datatype property in RiC-O, and if it has been specified that this
        is not to be permitted
        """

        def __init__(self, message: str) -> None:
            super().__init__(message)

    # END NotInKnownException
    # BEGIN _MetacharacterSubstituteParseException
    class _MetacharacterSubstituteParseException(Exception):
        def __init__(self, message: str) -> None:
            super().__init__(message)

    # END _MetacharacterSubstituteParseException
    # BEGIN MetacharacterException
    class MetacharacterException(Exception):
        """
        Can be thrown when calling the 'individual_blocks' function if an individual
        has an identifier (the text in the upper half of an individual node)
        containing an OWL metacharacter
        """

        def __init__(self, message: str) -> None:
            super().__init__(message)

    # END MetacharacterException
    # BEGIN _InvalidCapitalisationSchemeException
    class _InvalidCapitalisationSchemeException(Exception):
        def __init__(self, message: str) -> None:
            super().__init__(message)

    # END _InvalidCapitalisationSchemeException


# ===== core.rdf.control =====


class rdf_control_core:
    # BEGIN DrawIOParserGraph
    # override from draw_io_parser_graph.py
    class DrawIOParserGraph(Graph):
        """Graph subclass that records Draw.io specific metadata."""

        def __init__(
            self,
            *args,
            csv_path: Optional[str] = None,
            metacharacter_mode: str | None = None,
            **kwargs,
        ):
            super().__init__(*args, **kwargs)
            self.csv_path = csv_path
            self.metacharacter_mode = metacharacter_mode
            self.namespace_manager = NamespaceManager(self, bind_namespaces="none")

        def addN1(
            self,
            triple_1: tuple[Node, Node, Node],
            triples_N: list[tuple[Node, Node, Node]],
        ):
            """
            Add N+1: a triple and some other triples to the graph.

            Useful for cases like RR predicate-object map.
            """
            self.add(triple_1)
            self.addN(((s, p, o, self) for s, p, o in triples_N))

        @staticmethod
        def _extract_base_from_inputsource(source: InputSource):
            """
            Reuses some code from `TurtleParser.parse()`:
            https://rdflib.readthedocs.io/en/7.1.1/_modules/rdflib/plugins/parsers/notation3.html#TurtleParser

            The need for this function is dictated by the fact that
            rdflib seems NOT to read @base with `TurtleParser`
            into `base` property but rather resolves IRIs
            using base upon serialization. This leads to problems
            if graph is serialized and then parsed again repeatedly
            (i.e., `@base` is lost on repeat serialization).

            <https://stackoverflow.com/questions/43739259/how-do-i-get-the-base-uri-of-an-xml-file-using-rdflib>
            """
            graph = Graph()
            sink = RDFSink(graph)
            baseURI = graph.absolutize(
                source.getPublicId() or source.getSystemId() or ""
            )
            p = SinkParser(
                sink,
                baseURI=graph.absolutize(
                    source.getPublicId() or source.getSystemId() or ""
                ),
                turtle=True,
            )
            stream = source.getCharacterStream()
            if not stream:
                stream = source.getByteStream()
            p.loadStream(stream)
            baseURI = p._baseURI
            return baseURI

        @classmethod
        def extract_base_from_turtle(cls, turtle_str: str) -> str:
            """
            Parse the given Turtle document (string) and return
            the base URI used during parsing.
            """
            source = InputSource()
            source.setCharacterStream(StringIO(turtle_str))
            return cls._extract_base_from_inputsource(source)

        def _inject_base_from_parse_kwargs(self, **kwargs):
            if getattr(self, "base", None):
                return
            self.base = self._extract_base_from_inputsource(
                create_input_source(
                    source=kwargs.get("source"),
                    publicID=kwargs.get("publicID"),
                    location=kwargs.get("location"),
                    file=kwargs.get("file"),
                    data=kwargs.get("data"),
                    format=kwargs.get("format"),
                )
            )

        def parse(self, *args, **kwargs):
            """
            Same as in `super()` but injects `base` from Turtle
            if not already set and if available, thus making
            it persist across reserialiation/parsing cycles.

            Also see docstring for `_extract_base_from_inputsource()`.
            """
            super().parse(*args, **kwargs)
            self._inject_base_from_parse_kwargs(**kwargs)

    # END DrawIOParserGraph
    # BEGIN serialise_to_graph
    # override from rdf_serializer.py
    def serialise_to_graph(
        blocks: Blocks,
        object_properties: set[str],
        datatype_properties: set[str],
        serialisation_config: SerialisationConfig,
        prefixes: dict,
        graph_cls: Type = Graph,
        graph_kwargs: Optional[Dict[str, Any]] = None,
    ) -> DrawIOParserGraph:
        """Serialize blocks to RDF graph with regular triples."""
        RDFSerializer = pipeline.core.rdf.control.RDFSerializer
        if os.getenv("DEBUG") == "true":
            dump_blocks = pipeline.core.internal.control.dump_blocks
            dump_blocks(
                blocks, object_properties, datatype_properties, "tmp/blocks.json"
            )
        graph_kwargs = graph_kwargs or {}
        graph = graph_cls(**graph_kwargs)
        serializer = RDFSerializer(
            blocks,
            object_properties,
            datatype_properties,
            serialisation_config,
            prefixes,
            graph,
        )
        serializer.setup_namespaces()
        serializer.add_preamble()
        serializer.declare_properties()
        serializer.serialize_all_individuals()
        serializer.add_decoration_notes()
        if os.getenv("DEBUG") == "true":
            graph.serialize("tmp/graph.ttl", format="turtle")
        return graph

    # END serialise_to_graph


